/**
 * Creates a JSON Response with the given data and status code.
 *
 * @param {unknown} data - The data to serialize as JSON.
 * @param {number} [status=200] - The HTTP status code.
 * @returns {Response} A Response with JSON body and Content-Type header.
 */
export const jsonResponse = (data: unknown, status: number = 200): Response => {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
    },
  })
}

describe('jsonResponse', () => {
  it('should return a Response with JSON-stringified body', async () => {
    const { jsonResponse } = await import('./body')
    const res = jsonResponse({ message: 'hello' })
    const body = await res.json()
    expect(body).toEqual({ message: 'hello' })
  })

  it('should set Content-Type to application/json', async () => {
    const { jsonResponse } = await import('./body')
    const res = jsonResponse({ ok: true })
    expect(res.headers.get('Content-Type')).toBe('application/json')
  })

  it('should default status to 200', async () => {
    const { jsonResponse } = await import('./body')
    const res = jsonResponse({ ok: true })
    expect(res.status).toBe(200)
  })

  it('should use custom status when provided', async () => {
    const { jsonResponse } = await import('./body')
    const res = jsonResponse({ error: 'not found' }, 404)
    expect(res.status).toBe(404)
    const body = await res.json()
    expect(body).toEqual({ error: 'not found' })
  })

  it('should handle arrays', async () => {
    const { jsonResponse } = await import('./body')
    const res = jsonResponse([1, 2, 3])
    const body = await res.json()
    expect(body).toEqual([1, 2, 3])
  })

  it('should handle nested objects', async () => {
    const { jsonResponse } = await import('./body')
    const data = { user: { name: 'Alice', tags: ['admin', 'user'] } }
    const res = jsonResponse(data)
    const body = await res.json()
    expect(body).toEqual(data)
  })
})
